{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/ParameterListWrappingRuleReproduceTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.MAX_LINE_LENGTH_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class ParameterListWrappingRuleReproduceTest {
    private val parameterListWrappingRuleAssertThat =
        assertThatRule(
            provider = { ParameterListWrappingRule() },
            additionalRuleProviders =
                setOf(
                    RuleProvider { IndentationRule() },
                ),
        )

    @Test
    fun `Issue 1324 - Unnecessary newline before open parenthesis on nullable function type with wrapped parameters`() {
        val code =
            """
            val foo1: ((s1: String, s2: String, s3: String, s4: String, s5: String, s6: String) -> Unit)? = null
            """.trimIndent()

        // The expected formatted code that causes the issue (according to the report)
        // Note: The reporter says:
        // "Auto-correct by the parameter-list-wrapping resolves the max line length violation and results in code below: ... 
        // but that same rule immediately reports now another lint error ... Unnecessary newline before '('"
        // So we expect the rule to produce this output, and then NOT report "Unnecessary newline" on the output.

        val formattedCode =
            """
            val foo1: (
                (
                    s1: String,
                    s2: String,
                    s3: String,
                    s4: String,
                    s5: String,
                    s6: String
                ) -> Unit
            )? = null
            """.trimIndent()

        parameterListWrappingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 60) // Force wrapping
            .isFormattedAs(formattedCode)
    }
}
"}

