 40→public class ParameterListWrappingRule :
 41→    StandardRule(
 42→        id = "parameter-list-wrapping",
 43→        usesEditorConfigProperties =
 44→            setOf(
 45→                CODE_STYLE_PROPERTY,
 46→                INDENT_SIZE_PROPERTY,
 47→                INDENT_STYLE_PROPERTY,
 48→                MAX_LINE_LENGTH_PROPERTY,
 49→            ),
 50→    ) {
 51→    private var codeStyle = CODE_STYLE_PROPERTY.defaultValue
 52→    private var indentConfig = IndentConfig.DEFAULT_INDENT_CONFIG
 53→    private var maxLineLength = MAX_LINE_LENGTH_PROPERTY.defaultValue
 54→
 55→    override fun beforeFirstNode(editorConfig: EditorConfig) {
 56→        codeStyle = editorConfig[CODE_STYLE_PROPERTY]
 57→        maxLineLength = editorConfig[MAX_LINE_LENGTH_PROPERTY]
 58→        indentConfig =
 59→            IndentConfig(
 60→                indentStyle = editorConfig[INDENT_STYLE_PROPERTY],
 61→                tabWidth = editorConfig[INDENT_SIZE_PROPERTY],
 62→            )
 63→        if (indentConfig.disabled) {
 64→            stopTraversalOfAST()
 65→        }
 66→    }
 67→
 68→    override fun beforeVisitChildNodes(
 69→        node: ASTNode,
 70→        autoCorrect: Boolean,
 71→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 72→    ) {
 73→        when (node.elementType) {
 74→            NULLABLE_TYPE -> wrapNullableType(node, emit, autoCorrect)
 75→            VALUE_PARAMETER_LIST -> {
 76→                if (node.needToWrapParameterList()) {
 77→                    wrapParameterList(node, emit, autoCorrect)
 78→                }
 79→            }
 80→        }
 81→    }
 82→
 83→    private fun wrapNullableType(
 84→        node: ASTNode,
 85→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 86→        autoCorrect: Boolean,
 87→    ) {
 88→        require(node.elementType == NULLABLE_TYPE)
 89→        node
 90→            .takeUnless {
 91→                // skip when max line length is not exceedd
 92→                (node.column - 1 + node.textLength) <= maxLineLength
 93→            }?.findChildByType(FUNCTION_TYPE)
 94→            ?.findChildByType(VALUE_PARAMETER_LIST)
 95→            ?.takeIf { it.findChildByType(VALUE_PARAMETER) != null }
 96→            ?.takeUnless { it.textContains('\n') }
 97→            ?.let {
 98→                node
 99→                    .children()
100→                    .forEach {
101→                        when (it.elementType) {
102→                            LPAR -> {
103→                                emit(
104→                                    it.startOffset,
105→                                    "Parameter of nullable type should be on a separate line (unless the type fits on a single line)",
106→                                    true,
107→                                )
108→                                if (autoCorrect) {
109→                                    it.upsertWhitespaceAfterMe(indentConfig.childIndentOf(node))
110→                                }
111→                            }
112→                            RPAR -> {
113→                                emit(it.startOffset, errorMessage(it), true)
114→                                if (autoCorrect) {
115→                                    it.upsertWhitespaceBeforeMe(indentConfig.parentIndentOf(node))
116→                                }
117→                            }
118→                        }
119→                    }
120→            }
121→    }
122→
123→    private fun ASTNode.needToWrapParameterList() =
124→        when {
125→            hasNoParameters() -> false
126→            codeStyle != ktlint_official && isPartOfFunctionLiteralInNonKtlintOfficialCodeStyle() -> false
127→            codeStyle == ktlint_official && isPartOfFunctionLiteralStartingOnSameLineAsClosingParenthesisOfPrecedingReferenceExpression() ->
128→                false
129→            textContains('\n') -> true
130→            codeStyle == ktlint_official && containsAnnotatedParameter() -> true
131→            exceedsMaxLineLength() -> true
132→            else -> false
133→        }
134→
135→    private fun ASTNode.hasNoParameters(): Boolean {
136→        require(elementType == VALUE_PARAMETER_LIST)
137→        return firstChildNode?.treeNext?.elementType == RPAR
138→    }
139→
140→    private fun ASTNode.isPartOfFunctionLiteralInNonKtlintOfficialCodeStyle(): Boolean {
141→        require(elementType == VALUE_PARAMETER_LIST)
142→        return treeParent?.elementType == FUNCTION_LITERAL
143→    }
144→
145→    private fun ASTNode.isPartOfFunctionLiteralStartingOnSameLineAsClosingParenthesisOfPrecedingReferenceExpression(): Boolean {
146→        require(elementType == VALUE_PARAMETER_LIST)
147→        return firstChildLeafOrSelf()
148→            .let { startOfFunctionLiteral ->
149→                treeParent
150→                    ?.takeIf { it.elementType == FUNCTION_LITERAL }
151→                    ?.prevCodeLeaf()
152→                    ?.takeIf { it.treeParent.elementType == ElementType.VALUE_ARGUMENT_LIST }
153→                    ?.takeIf { it.treeParent.treeParent.elementType == ElementType.CALL_EXPRESSION }
154→                    ?.leaves()
155→                    ?.takeWhile { it != startOfFunctionLiteral }
156→                    ?.none { it.isWhiteSpaceWithNewline() }
157→                    ?: false
158→            }
159→    }
160→
161→    private fun ASTNode.isFunctionTypeWrappedInNullableType(): Boolean {
162→        require(elementType == VALUE_PARAMETER_LIST)
163→        return treeParent.elementType == FUNCTION_TYPE && treeParent?.treeParent?.elementType == NULLABLE_TYPE
164→    }
165→
166→    private fun ASTNode.containsAnnotatedParameter(): Boolean {
167→        require(elementType == VALUE_PARAMETER_LIST)
168→        return this.children()
169→            .filter { it.elementType == VALUE_PARAMETER }
170→            .any { it.isAnnotated() }
171→    }
172→
173→    private fun ASTNode.isAnnotated() =
174→        findChildByType(ElementType.MODIFIER_LIST)
175→            ?.children()
176→            .orEmpty()
177→            .any { it.elementType == ElementType.ANNOTATION_ENTRY }
178→
179→    private fun wrapParameterList(
180→        node: ASTNode,
181→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
182→        autoCorrect: Boolean,
183→    ) {
184→        node
185→            .children()
186→            .forEach { child -> wrapParameterInList(child, emit, autoCorrect) }
187→    }
188→
189→    private fun intendedIndent(child: ASTNode): String =
190→        when {
191→            // IDEA quirk:
192→            // fun <
193→            //     T,
194→            //     R> test(
195→            //     param1: T
196→            //     param2: R
197→            // )
198→            // instead of
199→            // fun <
200→            //     T,
201→            //     R> test(
202→            //         param1: T
203→            //         param2: R
204→            //     )
205→            child.treeParent.hasTypeParameterListInFront() -> -1
206→
207→            else -> 0
208→        }.let {
209→            if (child.elementType == VALUE_PARAMETER) {
210→                it + 1
211→            } else {
212→                it
213→            }
214→        }.let { indentLevelFix ->
215→            val indentLevel =
216→                indentConfig
217→                    .indentLevelFrom(child.treeParent.indent(false))
218→                    .plus(indentLevelFix)
219→            "\n" + indentConfig.indent.repeat(indentLevel)
220→        }
221→
222→    private fun wrapParameterInList(
223→        child: ASTNode,
224→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
225→        autoCorrect: Boolean,
226→    ) {
227→        when (child.elementType) {
228→            LPAR -> {
229→                val prevLeaf = child.prevLeaf()
230→                if (prevLeaf is PsiWhiteSpace && prevLeaf.textContains('\n')) {
231→                    emit(child.startOffset, errorMessage(child), true)
232→                    if (autoCorrect) {
233→                        prevLeaf.delete()
234→                    }
235→                }
236→            }
237→            VALUE_PARAMETER,
238→            RPAR,
239→            -> {
240→                // aiming for
241→                // ... LPAR
242→                // <line indent + indentSize> VALUE_PARAMETER...
243→                // <line indent> RPAR
244→                val intendedIndent = intendedIndent(child)
245→                val prevLeaf = child.prevLeaf()
246→                if (prevLeaf is PsiWhiteSpace) {
247→                    if (prevLeaf.getText().contains("\n")) {
248→                        // The current child is already wrapped to a new line. Checking and fixing the
249→                        // correct size of the indent is the responsibility of the IndentationRule.
250→                        return
251→                    } else {
252→                        // The current child needs to be wrapped to a newline.
253→                        emit(child.startOffset, errorMessage(child), true)
254→                        if (autoCorrect) {
255→                            // The indentation is purely based on the previous leaf only. Note that in
256→                            // autoCorrect mode the indent rule, if enabled, runs after this rule and
257→                            // determines the final indentation. But if the indent rule is disabled then the
258→                            // indent of this rule is kept.
259→                            (prevLeaf as LeafPsiElement).rawReplaceWithText(intendedIndent)
260→                        }
261→                    }
262→                } else {
263→                    // Insert a new whitespace element in order to wrap the current child to a new line.
264→                    emit(child.startOffset, errorMessage(child), true)
265→                    if (autoCorrect) {
266→                        child.treeParent.addChild(PsiWhiteSpaceImpl(intendedIndent), child)
267→                    }
268→                }
269→                // Indentation of child nodes need to be fixed by the IndentationRule.
270→            }
271→        }
272→    }
273→
274→    private fun ASTNode.exceedsMaxLineLength() = (column - 1 + textLength) > maxLineLength && !textContains('\n')
275→
276→    private fun errorMessage(node: ASTNode) =
277→        when (node.elementType) {
278→            LPAR -> """Unnecessary newline before "(""""
279→            VALUE_PARAMETER ->
280→                "Parameter should start on a newline"
281→            RPAR -> """Missing newline before ")""""
282→            else -> throw UnsupportedOperationException()
283→        }
284→
285→    private fun ASTNode.hasTypeParameterListInFront(): Boolean {
286→        val parent = this.treeParent
287→        val typeParameterList =
288→            if (parent.elementType == PRIMARY_CONSTRUCTOR) {
289→                parent.prevSibling { it.elementType == TYPE_PARAMETER_LIST }
290→            } else {
291→                parent.children().firstOrNull { it.elementType == TYPE_PARAMETER_LIST }
292→            }
293→        val typeListNode =
294→            typeParameterList
295→                ?: parent.psi.collectDescendantsOfType<KtTypeArgumentList>().firstOrNull()?.node
296→                ?: return false
297→        return typeListNode.children().any { it.isWhiteSpaceWithNewline() }
298→    }
299→}
